    private String createErrorResponse(String message) {
        StringBuilder response = new StringBuilder();
        response.append("<response>");
        response.append("<status>error</status>");
        response.append("<message>").append(escapeXml(message)).append("</message>");
        response.append("</response>");
        return response.toString();
    }

    private String createValidationResponse(boolean isValid, String message) {
        StringBuilder response = new StringBuilder();
        response.append("<response>");
        response.append("<status>").append(isValid ? "valid" : "invalid").append("</status>");
        response.append("<message>").append(escapeXml(message)).append("</message>");
        response.append("</response>");
        return response.toString();
    }

    private int countRecords(Map<String, Object> data) {
        int count = 1;
        if (data.containsKey("children")) {
            List<Map<String, Object>> children = (List<Map<String, Object>>) data.get("children");
            for (Map<String, Object> child : children) {
                if (child.containsKey("content")) {
                    count += countRecords((Map<String, Object>) child.get("content"));
                }
            }
        }
        return count;
    }

    private String escapeXml(String text) {
        if (text == null) {
            return "";
        }
        return text.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&apos;");
    }

